import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Captcha from "../../components/Captcha";

function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [captchaInput, setCaptchaInput] = useState("");
  const [captchaCode, setCaptchaCode] = useState("");
  const [error, setError] = useState("");

  const handleLogin = () => {
    if (!email || !password || !captchaInput) {
      setError("All fields are required");
      return;
    }
    if (captchaInput.toUpperCase() !== captchaCode) {
      setError("Captcha is incorrect");
      return;
    }
    setError("");

    // Simple role detection for demo:
    if (email.includes("admin")) localStorage.setItem("role", "admin");
    else if (email.includes("instructor")) localStorage.setItem("role", "instructor");
    else if (email.includes("student")) localStorage.setItem("role", "student");
    else localStorage.setItem("role", "content");

    const role = localStorage.getItem("role");
    if (role === "admin") navigate("/admin");
    else if (role === "instructor") navigate("/instructor");
    else if (role === "student") navigate("/student");
    else navigate("/content");
  };

  return (
    <div className="container d-flex justify-content-center align-items-center vh-100">
      <div className="card p-4 shadow" style={{ width: "400px" }}>
        <h3 className="text-center mb-4">NexaLearn LMS</h3>
        {error && <div className="alert alert-danger">{error}</div>}

        <input
          type="email"
          className="form-control mb-3"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          className="form-control mb-3"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <Captcha onChange={setCaptchaCode} />

        <input
          type="text"
          className="form-control mb-3 mt-2"
          placeholder="Enter verification code"
          value={captchaInput}
          onChange={(e) => setCaptchaInput(e.target.value)}
        />

        <button className="btn btn-primary w-100" onClick={handleLogin}>
          Login
        </button>

        <p className="mt-3 text-center">
          Don't have an account? <a href="/register">Register</a>
        </p>
      </div>
    </div>
  );
}

export default Login;
